fn main() {
    let cache = |x: i32| -> i32 {
        static mut results: Vec<i32> = vec![];
        unsafe {
            if x as usize >= results.len() {
                results.resize(x as usize + 1, 0);
            }
            results[x as usize]
        }
    };

    println!("{}", cache(5));
}

